#include<bits/stdc++.h>
using namespace std;
const long long N=4010,M=100010;
long long head[N],now[N],tot=1,d[N],n,m,s,t;
bool vis[N];
struct edge
{
    long long to,flow,nxt;
}e[M];
void add1(long long u,long long v,long long w)
{
    e[++tot]={v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    memset(d,0,sizeof(d));
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].flow;
            if(val&&!d[v])
            {
                d[v]=d[t]+1;
                if(v==::t)
                {
                    return true;
                }
                q.push(v);
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to;
        if(d[v]==d[x]+1&&e[i].flow)
        {
            long long tmp=dfs(v,min(flow,e[i].flow));
            e[i].flow-=tmp;
            e[i^1].flow+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(head));
        ans+=dfs(s,2e9);
    }
    return ans;
}
long long a[100010],b[100010];
map<long long,long long> mp;
int main()
{
    long long T;
    scanf("%lld",&T);
    while(T--)
    {
        mp.clear();
        ::tot=1;
        memset(e,0,sizeof(e));
        memset(head,0,sizeof(head));
        scanf("%lld%lld",&n,&m);
        s=n+m+1;
        t=s+1;
        long long tot=t;
        for(long long i=1;i<=n;i++)
        {
            add(s,i,1);
            scanf("%lld",&a[i]);
            for(long long j=2;j*j<=a[i];j++)
            {
                if(a[i]%j==0)
                {
                    if(!mp[j])
                    {
                        mp[j]=++tot;
                    }
                    add(i,mp[j],1);
                    while(a[i]%j==0)
                    {
                        a[i]/=j;
                    }
                }
            }
            if(a[i]>1)
            {
                if(!mp[a[i]])
                {
                    mp[a[i]]=++tot;
                }
                add(i,mp[a[i]],1);
            }
        }
        for(long long i=1;i<=m;i++)
        {
            add(i+n,t,1);
            scanf("%lld",&b[i]);
            for(long long j=2;j*j<=b[i];j++)
            {
                if(b[i]%j==0)
                {
                    if(!mp[j])
                    {
                        mp[j]=++tot;
                    }
                    add(mp[j],i+n,1);
                    while(b[i]%j==0)
                    {
                        b[i]/=j;
                    }
                }
            }
            if(b[i]>1)
            {
                if(!mp[b[i]])
                {
                    mp[b[i]]=++tot;
                }
                add(mp[b[i]],i+n,1);
            }
        }
        printf("%lld\n",dinic());
    }
    return 0;
}
